    // -- Fixture resolution --

    #[test]
    fn resolve_prefers_function_over_file_over_global() {
        let global_fixture = MockFixture {
            value_space: MockValueSpace::FixedSet {
                values: vec![serde_json::json!("global")],
            },
            return_type: None,
            expectations: None,
        };
        let file_fixture = MockFixture {
            value_space: MockValueSpace::FixedSet {
                values: vec![serde_json::json!("file")],
            },
            return_type: None,
            expectations: None,
        };
        let func_fixture = MockFixture {
            value_space: MockValueSpace::FixedSet {
                values: vec![serde_json::json!("function")],
            },
            return_type: None,
            expectations: None,
        };

        let config = MockFixtureConfig {
            global: HashMap::from([("dep".to_string(), global_fixture)]),
            files: HashMap::from([(
                "src/auth.ts".to_string(),
                HashMap::from([("dep".to_string(), file_fixture)]),
            )]),
            functions: HashMap::from([(
                "src/auth.ts::validate".to_string(),
                HashMap::from([("dep".to_string(), func_fixture)]),
            )]),
        };

        // Function scope wins
        let resolved = resolve_fixture(&config, "src/auth.ts::validate", "dep").unwrap();
        assert!(matches!(
            &resolved.value_space,
            MockValueSpace::FixedSet { values } if values[0] == serde_json::json!("function")
        ));

        // Without function scope, file wins
        let resolved = resolve_fixture(&config, "src/auth.ts::other", "dep").unwrap();
        assert!(matches!(
            &resolved.value_space,
            MockValueSpace::FixedSet { values } if values[0] == serde_json::json!("file")
        ));

        // Without file scope, global wins
        let resolved = resolve_fixture(&config, "src/other.ts::foo", "dep").unwrap();
        assert!(matches!(
            &resolved.value_space,
            MockValueSpace::FixedSet { values } if values[0] == serde_json::json!("global")
        ));

        // Unknown symbol returns None
        assert!(resolve_fixture(&config, "src/auth.ts::validate", "unknown").is_none());
    }

