//! User mock fixtures with `MockValueSpace` policy.
//!
//! Loaded from `.shatter/config.yaml` under `mock_fixtures`. Supports:
//! - **Scoping**: global, file-level, and `file::function`-level fixtures
//! - **Policies**: `FixedSet`, `Autonomous`, `Seeded`, `LiveFirst`
//! - **Expectations**: `called_with` patterns and `call_count` bounds
//! - **Type validation**: mismatches between declared return values and the
//!   dependency's return type are reported before exploration begins
//!
//! Fixture resolution: function-scoped > file-scoped > global.

use std::collections::HashMap;

use serde::{Deserialize, Serialize};
use serde_json::Value;

use crate::types::TypeInfo;

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/// Default call-count minimum when no explicit lower bound is given.
pub const DEFAULT_CALL_COUNT_MIN: u32 = 0;

/// Maximum number of return values allowed in a single FixedSet fixture.
pub const MAX_FIXED_SET_VALUES: usize = 1000;

// ---------------------------------------------------------------------------
// MockValueSpace policy
// ---------------------------------------------------------------------------

/// Controls how mock return values are produced during exploration.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "policy", rename_all = "snake_case")]
pub enum MockValueSpace {
    /// Return values drawn from a fixed, user-supplied set (cycled in order).
    FixedSet {
        /// Ordered list of return values to cycle through.
        values: Vec<Value>,
    },
    /// Shatter generates return values autonomously based on the return type.
    Autonomous,
    /// The user supplies seed values; Shatter mutates them to explore variants.
    Seeded {
        /// Seed return values that Shatter can mutate.
        seeds: Vec<Value>,
    },
    /// Try the real implementation first; fall back to the fixture on error.
    LiveFirst {
        /// Fallback return values when the live call fails.
        fallback: Vec<Value>,
    },
}

// ---------------------------------------------------------------------------
// Expectations
// ---------------------------------------------------------------------------

/// Expected call-argument pattern for a mock — used for post-execution validation.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct CalledWithPattern {
    /// Positional argument matchers. `null` means "any value".
    pub args: Vec<Value>,
}

/// Post-execution expectations attached to a mock fixture.
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct MockExpectation {
    /// If set, at least one call must match each pattern.
    #[serde(default)]
    pub called_with: Vec<CalledWithPattern>,

    /// Minimum number of times the mock must be called.
    #[serde(default)]
    pub call_count_min: Option<u32>,

    /// Maximum number of times the mock may be called.
    #[serde(default)]
    pub call_count_max: Option<u32>,
}

// ---------------------------------------------------------------------------
// MockFixture (single entry)
// ---------------------------------------------------------------------------

/// A single mock fixture: value-space policy + optional expectations.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct MockFixture {
    /// How return values are produced.
    pub value_space: MockValueSpace,

    /// Expected return type (for type validation). When absent, validation is skipped.
    #[serde(default)]
    pub return_type: Option<TypeInfo>,

    /// Post-execution expectations.
    #[serde(default)]
    pub expectations: Option<MockExpectation>,
}

// ---------------------------------------------------------------------------
// Scoped fixture config (YAML structure)
// ---------------------------------------------------------------------------

/// Top-level `mock_fixtures` block in `.shatter/config.yaml`.
///
/// Three scoping tiers:
/// - `global`: applies to all files and functions unless overridden
/// - `files`: keyed by file path glob, applies to all functions in matching files
/// - `functions`: keyed by `file::function` identifier, highest precedence
#[derive(Debug, Clone, Default, PartialEq, Serialize, Deserialize)]
pub struct MockFixtureConfig {
    /// Global fixtures keyed by dependency symbol.
    #[serde(default)]
    pub global: HashMap<String, MockFixture>,

    /// File-scoped fixtures: `{ "src/auth.ts": { "db.query": MockFixture } }`.
    #[serde(default)]
    pub files: HashMap<String, HashMap<String, MockFixture>>,

    /// Function-scoped fixtures: `{ "src/auth.ts::validateToken": { "db.query": MockFixture } }`.
    #[serde(default)]
    pub functions: HashMap<String, HashMap<String, MockFixture>>,
}

// ---------------------------------------------------------------------------
// Type validation
// ---------------------------------------------------------------------------

/// A type mismatch found during pre-exploration validation.
#[derive(Debug, Clone, PartialEq)]
pub struct TypeMismatch {
    /// Scope where the fixture was declared (e.g. "global", "file:src/auth.ts").
    pub scope: String,
    /// The dependency symbol.
    pub symbol: String,
    /// The declared return type from the fixture.
    pub declared_type: TypeInfo,
    /// The actual return type from static analysis.
    pub actual_type: TypeInfo,
    /// Human-readable explanation.
    pub message: String,
}

/// Validate that fixture return values are compatible with the declared return type.
///
/// Returns a list of mismatches. An empty list means all fixtures are valid.
pub fn validate_fixture_types(
    config: &MockFixtureConfig,
    known_deps: &HashMap<String, TypeInfo>,
) -> Vec<TypeMismatch> {
    let mut mismatches = Vec::new();

    // Validate global fixtures
    for (symbol, fixture) in &config.global {
        if let Some(actual_type) = known_deps.get(symbol) {
            validate_single_fixture(
                "global",
                symbol,
                fixture,
                actual_type,
                &mut mismatches,
            );
        }
    }

    // Validate file-scoped fixtures
    for (file_key, fixtures) in &config.files {
        for (symbol, fixture) in fixtures {
            if let Some(actual_type) = known_deps.get(symbol) {
                validate_single_fixture(
                    &format!("file:{file_key}"),
                    symbol,
                    fixture,
                    actual_type,
                    &mut mismatches,
                );
            }
        }
    }

    // Validate function-scoped fixtures
    for (func_key, fixtures) in &config.functions {
        for (symbol, fixture) in fixtures {
            if let Some(actual_type) = known_deps.get(symbol) {
                validate_single_fixture(
                    &format!("function:{func_key}"),
                    symbol,
                    fixture,
                    actual_type,
                    &mut mismatches,
                );
            }
        }
    }

    mismatches
}

fn validate_single_fixture(
    scope: &str,
    symbol: &str,
    fixture: &MockFixture,
    actual_type: &TypeInfo,
    mismatches: &mut Vec<TypeMismatch>,
) {
    let declared = match &fixture.return_type {
        Some(t) => t,
        None => return, // No declared type — skip validation
    };

    if !types_compatible(declared, actual_type) {
        mismatches.push(TypeMismatch {
            scope: scope.to_string(),
            symbol: symbol.to_string(),
            declared_type: declared.clone(),
            actual_type: actual_type.clone(),
            message: format!(
                "fixture for '{symbol}' in {scope} declares return type {declared:?} \
                 but static analysis found {actual_type:?}"
            ),
        });
    }
}

/// Check whether `declared` is compatible with `actual`.
///
/// Compatibility rules:
/// - Identical types are always compatible
/// - `Unknown` on either side is compatible (no information to contradict)
/// - `Nullable { inner }` is compatible if `inner` is compatible with the other
/// - `Union { variants }` is compatible if any variant is compatible
/// - `Int` and `Float` are mutually compatible (numeric widening)
fn types_compatible(declared: &TypeInfo, actual: &TypeInfo) -> bool {
    if declared == actual {
        return true;
    }

    // Unknown is always compatible — it means "we don't know"
    if matches!(declared, TypeInfo::Unknown) || matches!(actual, TypeInfo::Unknown) {
        return true;
    }

    // Numeric widening: Int <-> Float
    if matches!(
        (declared, actual),
        (TypeInfo::Int, TypeInfo::Float) | (TypeInfo::Float, TypeInfo::Int)
    ) {
        return true;
    }

    // Nullable: unwrap and check inner compatibility
    if let TypeInfo::Nullable { inner } = declared {
        if types_compatible(inner, actual) {
            return true;
        }
    }
    if let TypeInfo::Nullable { inner } = actual {
        if types_compatible(declared, inner) {
            return true;
        }
    }

    // Union: compatible if any variant matches
    if let TypeInfo::Union { variants } = declared {
        if variants.iter().any(|v| types_compatible(v, actual)) {
            return true;
        }
    }
    if let TypeInfo::Union { variants } = actual {
        if variants.iter().any(|v| types_compatible(declared, v)) {
            return true;
        }
    }

    false
}

// ---------------------------------------------------------------------------
// Fixture resolution
// ---------------------------------------------------------------------------

/// Resolve the effective fixture for a dependency symbol, given the function context.
///
/// Resolution order (first match wins): function > file > global.
/// `function_id` is in `"file::function"` format (e.g. `"src/auth.ts::validateToken"`).
pub fn resolve_fixture<'a>(
    config: &'a MockFixtureConfig,
    function_id: &str,
    symbol: &str,
) -> Option<&'a MockFixture> {
    // Function scope: exact match on function_id
    if let Some(fixtures) = config.functions.get(function_id) {
        if let Some(fixture) = fixtures.get(symbol) {
            return Some(fixture);
        }
    }

    // File scope: extract file part from "file::function"
    if let Some(file_part) = function_id.split("::").next() {
        if let Some(fixtures) = config.files.get(file_part) {
            if let Some(fixture) = fixtures.get(symbol) {
                return Some(fixture);
            }
        }
    }

    // Global scope
    config.global.get(symbol)
}

// ---------------------------------------------------------------------------
// Expectation validation (post-execution)
// ---------------------------------------------------------------------------

/// Outcome of a single expectation check.
#[derive(Debug, Clone, PartialEq)]
pub struct ExpectationViolation {
    /// The dependency symbol.
    pub symbol: String,
    /// Human-readable description of the violation.
    pub message: String,
}

/// Recorded call data for a mock, collected during execution.
#[derive(Debug, Clone, Default)]
pub struct MockCallRecord {
    /// Arguments from each call.
    pub calls: Vec<Vec<Value>>,
}

/// Validate expectations against recorded call data.
///
/// Returns a list of violations. An empty list means all expectations are met.
pub fn validate_expectations(
    fixtures: &HashMap<String, MockFixture>,
    call_records: &HashMap<String, MockCallRecord>,
) -> Vec<ExpectationViolation> {
    let mut violations = Vec::new();

    for (symbol, fixture) in fixtures {
        let expectation = match &fixture.expectations {
            Some(e) => e,
            None => continue,
        };

        let record = call_records.get(symbol);
        let call_count = record.map_or(0, |r| r.calls.len() as u32);

        // call_count_min
        if let Some(min) = expectation.call_count_min {
            if call_count < min {
                violations.push(ExpectationViolation {
                    symbol: symbol.clone(),
                    message: format!(
                        "expected at least {min} calls to '{symbol}', got {call_count}"
                    ),
                });
            }
        }

        // call_count_max
        if let Some(max) = expectation.call_count_max {
            if call_count > max {
                violations.push(ExpectationViolation {
                    symbol: symbol.clone(),
                    message: format!(
                        "expected at most {max} calls to '{symbol}', got {call_count}"
                    ),
                });
            }
        }

        // called_with patterns
        if let Some(ref record) = record {
            for pattern in &expectation.called_with {
                let matched = record.calls.iter().any(|call_args| {
                    args_match_pattern(call_args, &pattern.args)
                });
                if !matched {
                    violations.push(ExpectationViolation {
                        symbol: symbol.clone(),
                        message: format!(
                            "no call to '{symbol}' matched pattern {:?}",
                            pattern.args
                        ),
                    });
                }
            }
        } else if !expectation.called_with.is_empty() {
            // No calls at all, but patterns expected
            violations.push(ExpectationViolation {
                symbol: symbol.clone(),
                message: format!(
                    "expected calls to '{symbol}' matching {} pattern(s), but mock was never called",
                    expectation.called_with.len()
                ),
            });
        }
    }

    violations
}

/// Check if actual call arguments match a `called_with` pattern.
///
/// `null` in the pattern means "any value" (wildcard).
/// All other values require exact JSON equality.
fn args_match_pattern(actual: &[Value], pattern: &[Value]) -> bool {
    if actual.len() != pattern.len() {
        return false;
    }
    actual.iter().zip(pattern).all(|(a, p)| {
        p.is_null() || a == p
    })
}

