            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: Some(MockExpectation {
                    call_count_min: None,
                    call_count_max: Some(1),
                    called_with: vec![],
                }),
            },
        )]);

        let records = HashMap::from([(
            "dep".to_string(),
            MockCallRecord {
                calls: vec![
                    vec![serde_json::json!(1)],
                    vec![serde_json::json!(2)],
                    vec![serde_json::json!(3)],
                ],
            },
        )]);

        let violations = validate_expectations(&fixtures, &records);
        assert_eq!(violations.len(), 1);
        assert!(violations[0].message.contains("at most 1"));
    }

    #[test]
    fn expectation_called_with_match() {
        let fixtures = HashMap::from([(
            "dep".to_string(),
            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: Some(MockExpectation {
                    call_count_min: None,
                    call_count_max: None,
                    called_with: vec![CalledWithPattern {
                        args: vec![serde_json::json!(42), Value::Null],
                    }],
                }),
            },
        )]);

        // Second arg is anything (null = wildcard)
        let records = HashMap::from([(
            "dep".to_string(),
            MockCallRecord {
                calls: vec![vec![serde_json::json!(42), serde_json::json!("anything")]],
            },
        )]);

        let violations = validate_expectations(&fixtures, &records);
        assert!(violations.is_empty());
    }

    #[test]
    fn expectation_called_with_no_match() {
        let fixtures = HashMap::from([(
            "dep".to_string(),
            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: Some(MockExpectation {
                    call_count_min: None,
                    call_count_max: None,
                    called_with: vec![CalledWithPattern {
                        args: vec![serde_json::json!(99)],
                    }],
                }),
            },
        )]);

        let records = HashMap::from([(
            "dep".to_string(),
            MockCallRecord {
                calls: vec![vec![serde_json::json!(1)]],
            },
        )]);

        let violations = validate_expectations(&fixtures, &records);
        assert_eq!(violations.len(), 1);
        assert!(violations[0].message.contains("no call"));
    }

    #[test]
    fn expectation_called_with_never_called() {
        let fixtures = HashMap::from([(
            "dep".to_string(),
            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: Some(MockExpectation {
                    call_count_min: None,
                    call_count_max: None,
                    called_with: vec![CalledWithPattern {
                        args: vec![serde_json::json!(1)],
                    }],
                }),
            },
        )]);

        let violations = validate_expectations(&fixtures, &HashMap::new());
        assert_eq!(violations.len(), 1);
        assert!(violations[0].message.contains("never called"));
    }

    #[test]
    fn no_expectations_produces_no_violations() {
        let fixtures = HashMap::from([(
            "dep".to_string(),
            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: None,
            },
        )]);

        let violations = validate_expectations(&fixtures, &HashMap::new());
        assert!(violations.is_empty());
    }

    #[test]
    fn all_expectations_pass() {
        let fixtures = HashMap::from([(
            "dep".to_string(),
            MockFixture {
                value_space: MockValueSpace::Autonomous,
                return_type: None,
                expectations: Some(MockExpectation {
                    call_count_min: Some(1),
                    call_count_max: Some(3),
                    called_with: vec![CalledWithPattern {
                        args: vec![serde_json::json!("hello")],
                    }],
                }),
            },
        )]);

        let records = HashMap::from([(
            "dep".to_string(),
            MockCallRecord {
                calls: vec![
                    vec![serde_json::json!("hello")],
                    vec![serde_json::json!("world")],
                ],
            },
        )]);

        let violations = validate_expectations(&fixtures, &records);
        assert!(violations.is_empty());
    }

    // -- args_match_pattern --

    #[test]
    fn args_match_exact() {
        assert!(args_match_pattern(
            &[serde_json::json!(1), serde_json::json!("x")],
            &[serde_json::json!(1), serde_json::json!("x")],
        ));
    }

    #[test]
    fn args_match_wildcard() {
        assert!(args_match_pattern(
            &[serde_json::json!(1), serde_json::json!("anything")],
            &[serde_json::json!(1), Value::Null],
        ));
    }

    #[test]
    fn args_mismatch_length() {
        assert!(!args_match_pattern(
            &[serde_json::json!(1)],
            &[serde_json::json!(1), serde_json::json!(2)],
        ));
    }

    #[test]
    fn args_mismatch_value() {
        assert!(!args_match_pattern(
            &[serde_json::json!(1)],
            &[serde_json::json!(2)],
        ));
    }

    // -- Type compatibility edge cases --

    #[test]
    fn identical_types_compatible() {
        assert!(types_compatible(&TypeInfo::Int, &TypeInfo::Int));
        assert!(types_compatible(&TypeInfo::Str, &TypeInfo::Str));
    }

    #[test]
    fn incompatible_types() {
        assert!(!types_compatible(&TypeInfo::Str, &TypeInfo::Bool));
        assert!(!types_compatible(&TypeInfo::Int, &TypeInfo::Str));
    }
}

// ---------------------------------------------------------------------------
// Property-based tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod property_tests {
    use super::*;
    use crate::test_arbitraries::{arb_json_value, arb_type_info};
    use proptest::prelude::*;

    fn arb_mock_value_space() -> BoxedStrategy<MockValueSpace> {
        prop_oneof![
            prop::collection::vec(arb_json_value(), 0..=3)
                .prop_map(|values| MockValueSpace::FixedSet { values }),
            Just(MockValueSpace::Autonomous),
            prop::collection::vec(arb_json_value(), 1..=3)
                .prop_map(|seeds| MockValueSpace::Seeded { seeds }),
            prop::collection::vec(arb_json_value(), 0..=3)
                .prop_map(|fallback| MockValueSpace::LiveFirst { fallback }),
        ]
        .boxed()
    }

    fn arb_mock_fixture() -> BoxedStrategy<MockFixture> {
        (
            arb_mock_value_space(),
            proptest::option::of(arb_type_info(1)),
        )
            .prop_map(|(value_space, return_type)| MockFixture {
                value_space,
                return_type,
                expectations: None,
            })
            .boxed()
    }

    proptest! {
        /// MockValueSpace roundtrips through JSON.
        #[test]
        fn mock_value_space_json_roundtrip(vs in arb_mock_value_space()) {
            let json = serde_json::to_string(&vs).expect("serialize");
            let deserialized: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(&vs, &deserialized);
        }

        /// MockFixture roundtrips through JSON.
        #[test]
        fn mock_fixture_json_roundtrip(fixture in arb_mock_fixture()) {
            let json = serde_json::to_string(&fixture).expect("serialize");
            let deserialized: MockFixture = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(&fixture, &deserialized);
        }

        /// MockValueSpace roundtrips through YAML.
        #[test]
        fn mock_value_space_yaml_roundtrip(vs in arb_mock_value_space()) {
            let yaml = serde_yaml::to_string(&vs).expect("serialize");
            let deserialized: MockValueSpace = serde_yaml::from_str(&yaml).expect("deserialize");
            prop_assert_eq!(&vs, &deserialized);
        }

        /// types_compatible is reflexive: every type is compatible with itself.
        #[test]
        fn type_compatibility_reflexive(t in arb_type_info(2)) {
            prop_assert!(types_compatible(&t, &t));
        }

        /// Unknown is compatible with any type.
        #[test]
        fn unknown_compatible_with_anything(t in arb_type_info(2)) {
            prop_assert!(types_compatible(&TypeInfo::Unknown, &t));
            prop_assert!(types_compatible(&t, &TypeInfo::Unknown));
        }

        /// resolve_fixture returns None for unknown symbols regardless of scope.
        #[test]
        fn resolve_fixture_unknown_symbol_is_none(func_id in "[a-z/]+::[a-z]+") {
            let config = MockFixtureConfig::default();
            prop_assert!(resolve_fixture(&config, &func_id, "nonexistent").is_none());
        }

        /// validate_expectations with no expectations always produces empty violations.
        #[test]
        fn no_expectations_no_violations(symbol in "[a-z_]+") {
            let fixtures = HashMap::from([(
                symbol,
                MockFixture {
                    value_space: MockValueSpace::Autonomous,
                    return_type: None,
                    expectations: None,
                },
            )]);
            let violations = validate_expectations(&fixtures, &HashMap::new());
            prop_assert!(violations.is_empty());
        }
    }
}
