                    expectations: None,
                },
            )]),
            ..Default::default()
        };

        let known_deps = HashMap::from([("dep".to_string(), TypeInfo::Bool)]);
        let mismatches = validate_fixture_types(&config, &known_deps);
        assert!(mismatches.is_empty());
    }

    #[test]
    fn unknown_type_is_always_compatible() {
        assert!(types_compatible(&TypeInfo::Unknown, &TypeInfo::Int));
        assert!(types_compatible(&TypeInfo::Str, &TypeInfo::Unknown));
    }

    #[test]
    fn nullable_compatible_with_inner() {
        let nullable_int = TypeInfo::Nullable {
            inner: Box::new(TypeInfo::Int),
        };
        assert!(types_compatible(&nullable_int, &TypeInfo::Int));
        assert!(types_compatible(&TypeInfo::Int, &nullable_int));
    }

    #[test]
    fn union_compatible_with_variant() {
        let union = TypeInfo::Union {
            variants: vec![TypeInfo::Int, TypeInfo::Str],
        };
        assert!(types_compatible(&union, &TypeInfo::Str));
        assert!(types_compatible(&TypeInfo::Int, &union));
        assert!(!types_compatible(&TypeInfo::Bool, &union));
    }

