// ---------------------------------------------------------------------------
// Property-based tests
// ---------------------------------------------------------------------------

#[cfg(test)]
mod property_tests {
    use super::*;
    use crate::test_arbitraries::{arb_json_value, arb_type_info};
    use proptest::prelude::*;

    fn arb_mock_value_space() -> BoxedStrategy<MockValueSpace> {
        prop_oneof![
            prop::collection::vec(arb_json_value(), 0..=3)
                .prop_map(|values| MockValueSpace::FixedSet { values }),
            Just(MockValueSpace::Autonomous),
            prop::collection::vec(arb_json_value(), 1..=3)
                .prop_map(|seeds| MockValueSpace::Seeded { seeds }),
            prop::collection::vec(arb_json_value(), 0..=3)
                .prop_map(|fallback| MockValueSpace::LiveFirst { fallback }),
        ]
        .boxed()
    }

    fn arb_mock_fixture() -> BoxedStrategy<MockFixture> {
        (
            arb_mock_value_space(),
            proptest::option::of(arb_type_info(1)),
        )
            .prop_map(|(value_space, return_type)| MockFixture {
                value_space,
                return_type,
                expectations: None,
            })
            .boxed()
    }

    proptest! {
        /// MockValueSpace roundtrips through JSON.
        #[test]
        fn mock_value_space_json_roundtrip(vs in arb_mock_value_space()) {
            let json = serde_json::to_string(&vs).expect("serialize");
            let deserialized: MockValueSpace = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(&vs, &deserialized);
        }

        /// MockFixture roundtrips through JSON.
        #[test]
        fn mock_fixture_json_roundtrip(fixture in arb_mock_fixture()) {
            let json = serde_json::to_string(&fixture).expect("serialize");
            let deserialized: MockFixture = serde_json::from_str(&json).expect("deserialize");
            prop_assert_eq!(&fixture, &deserialized);
        }

        /// MockValueSpace roundtrips through YAML.
        #[test]
        fn mock_value_space_yaml_roundtrip(vs in arb_mock_value_space()) {
            let yaml = serde_yaml::to_string(&vs).expect("serialize");
            let deserialized: MockValueSpace = serde_yaml::from_str(&yaml).expect("deserialize");
            prop_assert_eq!(&vs, &deserialized);
        }

        /// types_compatible is reflexive: every type is compatible with itself.
        #[test]
        fn type_compatibility_reflexive(t in arb_type_info(2)) {
            prop_assert!(types_compatible(&t, &t));
        }

        /// Unknown is compatible with any type.
        #[test]
        fn unknown_compatible_with_anything(t in arb_type_info(2)) {
            prop_assert!(types_compatible(&TypeInfo::Unknown, &t));
            prop_assert!(types_compatible(&t, &TypeInfo::Unknown));
        }

        /// resolve_fixture returns None for unknown symbols regardless of scope.
        #[test]
        fn resolve_fixture_unknown_symbol_is_none(func_id in "[a-z/]+::[a-z]+") {
            let config = MockFixtureConfig::default();
            prop_assert!(resolve_fixture(&config, &func_id, "nonexistent").is_none());
        }

        /// validate_expectations with no expectations always produces empty violations.
        #[test]
        fn no_expectations_no_violations(symbol in "[a-z_]+") {
            let fixtures = HashMap::from([(
                symbol,
                MockFixture {
                    value_space: MockValueSpace::Autonomous,
                    return_type: None,
                    expectations: None,
                },
            )]);
            let violations = validate_expectations(&fixtures, &HashMap::new());
            prop_assert!(violations.is_empty());
        }
    }
}
